/*
 * frexpf() test harness — prints (input_hex, mantissa_hex, exponent) triples.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly frexpf  (test_frexpf_opt.elf)
 *   2. Linked with toolchain's default frexpf        (test_frexpf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile float g_acc;
static int g_ex;

static void emit(float x)
{
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += frexpf(vx, &g_ex);
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#else
static void emit(float x)
{
    int ex;
    float r = frexpf(x, &ex);
    printf("%08lx %08lx %d\n",
           (unsigned long)f2u(x), (unsigned long)f2u(r), ex);
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#endif

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                       */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf */
    emit_u(0xff800000u);  /* -Inf */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                /* 2^-126, smallest normal */
    emit(-FLT_MIN);
    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    emit_u(0x7f7fffffu);          /* FLT_MAX */
    emit_u(0xff7fffffu);          /* -FLT_MAX */
    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0 */
    emit(1.0f);           /* 1.0 -> mantissa=0.5, exp=1 */
    emit_u(0x3f800001u);  /* one ULP above 1.0 */
    emit_u(0x3f7ffff0u);  /* a few ULPs below 1.0 */
    emit_u(0x3f800010u);  /* a few ULPs above 1.0 */
    emit(-1.0f);
    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0 */
    emit_u(0xbf800001u);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Powers of 2 (exponent switching points) (16) --- */
    emit_u(0x3a800000u);  /* 2^-10 */
    emit_u(0x3b000000u);  /* 2^-9 */
    emit_u(0x3b800000u);  /* 2^-8 */
    emit_u(0x3c000000u);  /* 2^-7 */
    emit_u(0x3c800000u);  /* 2^-6 */
    emit_u(0x3d000000u);  /* 2^-5 */
    emit_u(0x3d800000u);  /* 2^-4 */
    emit_u(0x3e000000u);  /* 2^-3 = 0.125 */
    emit_u(0x3e800000u);  /* 2^-2 = 0.25 */
    emit_u(0x3f000000u);  /* 2^-1 = 0.5 */
    emit_u(0x3f800000u);  /* 2^0  = 1.0 */
    emit_u(0x40000000u);  /* 2^1  = 2.0 */
    emit_u(0x40800000u);  /* 2^2  = 4.0 */
    emit_u(0x41000000u);  /* 2^3  = 8.0 */
    emit_u(0x41800000u);  /* 2^4  = 16.0 */
    emit_u(0x42000000u);  /* 2^5  = 32.0 */

    /* --- Section 6: Exact mantissa fractions (positive) (12) --- */
    emit(0.5f);    /* mantissa=0.5, exp=0 */
    emit(0.625f);  /* 0.5 * 1.25, exp=0 */
    emit(0.75f);   /* 0.5 * 1.5, exp=0 */
    emit(0.875f);  /* 0.5 * 1.75, exp=0 */
    emit(1.25f);   /* mantissa=0.625, exp=1 */
    emit(1.5f);    /* mantissa=0.75, exp=1 */
    emit(1.75f);   /* mantissa=0.875, exp=1 */
    emit(3.0f);    /* mantissa=0.75, exp=2 */
    emit(5.0f);    /* mantissa=0.625, exp=3 */
    emit(6.0f);    /* mantissa=0.75, exp=3 */
    emit(7.0f);    /* mantissa=0.875, exp=3 */
    emit(100.0f);  /* mantissa=0.78125, exp=7 */

    /* --- Section 7: Negative mirrors of section 6 (12) --- */
    emit(-0.5f);
    emit(-0.625f);
    emit(-0.75f);
    emit(-0.875f);
    emit(-1.25f);
    emit(-1.5f);
    emit(-1.75f);
    emit(-3.0f);
    emit(-5.0f);
    emit(-6.0f);
    emit(-7.0f);
    emit(-100.0f);

    /* --- Section 8: Large values (10) --- */
    emit(1.0e3f);
    emit(-1.0e3f);
    emit(1.0e7f);
    emit(-1.0e7f);
    emit(1.0e10f);
    emit(-1.0e10f);
    emit(1.0e20f);
    emit(-1.0e20f);
    emit(1.0e30f);
    emit(-1.0e30f);

    /* --- Section 9: Small normal values (10) --- */
    emit(1.0e-10f);
    emit(-1.0e-10f);
    emit(1.0e-20f);
    emit(-1.0e-20f);
    emit(1.0e-30f);
    emit(-1.0e-30f);
    emit_u(0x00800002u);  /* two ULPs above FLT_MIN */
    emit_u(0x80800002u);  /* two ULPs above -FLT_MIN toward zero */
    emit_u(0x01000000u);  /* 2^-126 * 2 = 2^-125: first normal with exp field 2 */
    emit_u(0x81000000u);  /* negative of above */

    /* --- Section 10: ULP neighbors of key mantissa boundaries (13) --- */
    emit_u(0x3effffffu);  /* one ULP below 0.5 */
    emit_u(0x3f000001u);  /* one ULP above 0.5 */
    emit_u(0x3f7ffffeu);  /* two ULPs below 1.0 */
    emit_u(0x3f800002u);  /* two ULPs above 1.0 */
    emit_u(0x3fffffffu);  /* one ULP below 2.0 */
    emit_u(0x40000001u);  /* one ULP above 2.0 */
    emit_u(0x407fffffu);  /* one ULP below 4.0 */
    emit_u(0x40800001u);  /* one ULP above 4.0 */
    emit_u(0x3f400000u);  /* 0.75: mid-point of [0.5, 1) */
    emit_u(0x3f600000u);  /* 0.875 */
    emit_u(0x3f200000u);  /* 0.625 */
    emit_u(0xbf400000u);  /* -0.75 */
    emit_u(0xbf600000u);  /* -0.875 */
}

/* ------------------------------------------------------------------ */

/* 7. Sweep [0.5, 2) mantissa range with integer base exponents */
static void test_sweep(void)
{
    float lo = 0.5f, hi = 2.0f;
    int nsteps = 100;
    float step = (hi - lo) / (float)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit(lo + (float)i * step);

    /* Negative */
    for (int i = 0; i <= nsteps; i++)
        emit(-(lo + (float)i * step));
}

/* 8. Sample [0.5, 1] every 2097152 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t start = 0x3f000000u; /* 0.5 */
    uint32_t end = 0x3f800000u;   /* 1.0 */
    for (uint32_t b = start; b <= end; b += 2097152)
        emit_u(b);
}

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
static void perf(float x)
{
    volatile float acc = 0.0f;
    int ex;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += frexpf(x+i, &ex);
    stopPFM;
    readResult();
    printf("perf %08lx: %08lx\n",
           (unsigned long)f2u(x),
           (unsigned long)f2u((float)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
